# ============================================================
# Language Switcher for Stream Deck — Self-Contained Installer
# Author : iH4xz — https://ih4xz.pro
# GitHub : https://github.com/iH4xz/lang-switcher-btn
# License: GPL-3.0
# ============================================================
# Plugin data is embedded below as base64-encoded ZIP
# ============================================================

Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing
Add-Type -AssemblyName System.IO.Compression.FileSystem
Add-Type -AssemblyName System.IO.Compression

$PLUGIN_NAME    = "Language Switcher"
$PLUGIN_VERSION = "1.0.0"
$PLUGIN_AUTHOR  = "iH4xz"
$PLUGIN_URL     = "https://ih4xz.pro/projects/lang-switcher-btn/"
$PLUGIN_FOLDER  = "com.ih4xz.langbutton.sdPlugin"
$PLUGINS_DIR    = "$env:APPDATA\Elgato\StreamDeck\Plugins"
$DEST_PATH      = Join-Path $PLUGINS_DIR $PLUGIN_FOLDER

# ---- Embedded plugin data (base64 ZIP) ----
$PLUGIN_B64 = ''

function Show-MB($msg, $title, $icon="Information", $buttons="OK") {
    return [System.Windows.Forms.MessageBox]::Show(
        $msg, $title,
        [System.Windows.Forms.MessageBoxButtons]::$buttons,
        [System.Windows.Forms.MessageBoxIcon]::$icon)
}

function Get-SDProcess { return Get-Process -Name "StreamDeck" -ErrorAction SilentlyContinue }

function Stop-SD {
    $p = Get-SDProcess
    if ($p) { $p | Stop-Process -Force; Start-Sleep -Milliseconds 1500 }
}

function Start-SD {
    $exe = "${env:ProgramFiles}\Elgato\StreamDeck\StreamDeck.exe"
    if (-not (Test-Path $exe)) { $exe = "${env:ProgramFiles(x86)}\Elgato\StreamDeck\StreamDeck.exe" }
    if (Test-Path $exe) { Start-Process $exe }
}

function Show-Form {
    $form = New-Object System.Windows.Forms.Form
    $form.Text            = "$PLUGIN_NAME Installer v$PLUGIN_VERSION"
    $form.Size            = New-Object System.Drawing.Size(480, 320)
    $form.StartPosition   = "CenterScreen"
    $form.FormBorderStyle = "FixedDialog"
    $form.MaximizeBox     = $false
    $form.MinimizeBox     = $false
    $form.BackColor       = [System.Drawing.Color]::FromArgb(15, 15, 26)

    $lbTitle = New-Object System.Windows.Forms.Label
    $lbTitle.Text      = "Language Switcher"
    $lbTitle.Font      = New-Object System.Drawing.Font("Segoe UI", 20, [System.Drawing.FontStyle]::Bold)
    $lbTitle.ForeColor = [System.Drawing.Color]::FromArgb(0, 212, 255)
    $lbTitle.Location  = New-Object System.Drawing.Point(20, 20)
    $lbTitle.Size      = New-Object System.Drawing.Size(440, 44)

    $lbSub = New-Object System.Windows.Forms.Label
    $lbSub.Text      = "Stream Deck Plugin  •  EN / ع  •  by $PLUGIN_AUTHOR"
    $lbSub.Font      = New-Object System.Drawing.Font("Segoe UI", 10)
    $lbSub.ForeColor = [System.Drawing.Color]::FromArgb(180, 180, 200)
    $lbSub.Location  = New-Object System.Drawing.Point(20, 68)
    $lbSub.Size      = New-Object System.Drawing.Size(440, 24)

    $sep = New-Object System.Windows.Forms.Label
    $sep.BackColor = [System.Drawing.Color]::FromArgb(40, 40, 70)
    $sep.Location  = New-Object System.Drawing.Point(20, 100)
    $sep.Size      = New-Object System.Drawing.Size(440, 1)

    $script:lbStatus = New-Object System.Windows.Forms.Label
    $script:lbStatus.Text      = "Click Install to begin."
    $script:lbStatus.Font      = New-Object System.Drawing.Font("Segoe UI", 10)
    $script:lbStatus.ForeColor = [System.Drawing.Color]::FromArgb(220, 220, 240)
    $script:lbStatus.Location  = New-Object System.Drawing.Point(20, 114)
    $script:lbStatus.Size      = New-Object System.Drawing.Size(440, 60)

    $script:pb = New-Object System.Windows.Forms.ProgressBar
    $script:pb.Minimum  = 0
    $script:pb.Maximum  = 100
    $script:pb.Value    = 0
    $script:pb.Style    = "Continuous"
    $script:pb.Location = New-Object System.Drawing.Point(20, 184)
    $script:pb.Size     = New-Object System.Drawing.Size(440, 16)

    $script:btnOK = New-Object System.Windows.Forms.Button
    $script:btnOK.Text      = "Install"
    $script:btnOK.Font      = New-Object System.Drawing.Font("Segoe UI", 11, [System.Drawing.FontStyle]::Bold)
    $script:btnOK.BackColor = [System.Drawing.Color]::FromArgb(0, 140, 180)
    $script:btnOK.ForeColor = [System.Drawing.Color]::White
    $script:btnOK.FlatStyle = "Flat"
    $script:btnOK.Location  = New-Object System.Drawing.Point(20, 220)
    $script:btnOK.Size      = New-Object System.Drawing.Size(200, 44)
    $script:btnOK.Cursor    = [System.Windows.Forms.Cursors]::Hand

    $script:btnCancel = New-Object System.Windows.Forms.Button
    $script:btnCancel.Text         = "Cancel"
    $script:btnCancel.Font         = New-Object System.Drawing.Font("Segoe UI", 11)
    $script:btnCancel.BackColor    = [System.Drawing.Color]::FromArgb(50, 50, 70)
    $script:btnCancel.ForeColor    = [System.Drawing.Color]::FromArgb(200, 200, 200)
    $script:btnCancel.FlatStyle    = "Flat"
    $script:btnCancel.Location     = New-Object System.Drawing.Point(260, 220)
    $script:btnCancel.Size         = New-Object System.Drawing.Size(200, 44)
    $script:btnCancel.Cursor       = [System.Windows.Forms.Cursors]::Hand
    $script:btnCancel.DialogResult = [System.Windows.Forms.DialogResult]::Cancel

    $lbFoot = New-Object System.Windows.Forms.Label
    $lbFoot.Text      = "$PLUGIN_URL  |  GPL-3.0 Open Source"
    $lbFoot.Font      = New-Object System.Drawing.Font("Segoe UI", 8)
    $lbFoot.ForeColor = [System.Drawing.Color]::FromArgb(100, 100, 130)
    $lbFoot.Location  = New-Object System.Drawing.Point(20, 277)
    $lbFoot.Size      = New-Object System.Drawing.Size(440, 18)

    $script:btnOK.Add_Click({
        $script:btnOK.Enabled     = $false
        $script:btnCancel.Enabled = $false
        Install-Plugin
    })

    $form.Controls.AddRange(@($lbTitle,$lbSub,$sep,$script:lbStatus,$script:pb,$script:btnOK,$script:btnCancel,$lbFoot))
    $form.CancelButton = $script:btnCancel
    return $form
}

function Set-Status($msg, $pct) {
    $script:lbStatus.Text  = $msg
    $script:pb.Value       = [Math]::Min($pct, 100)
    [System.Windows.Forms.Application]::DoEvents()
}

function Install-Plugin {
    try {
        Set-Status "Preparing plugin data..." 10

        # Decode the embedded base64 ZIP to a temp file
        $tmp = [System.IO.Path]::GetTempFileName() + ".zip"
        $bytes = [Convert]::FromBase64String($PLUGIN_B64)
        [System.IO.File]::WriteAllBytes($tmp, $bytes)

        Set-Status "Checking Stream Deck plugins folder..." 20
        if (-not (Test-Path $PLUGINS_DIR)) {
            New-Item -ItemType Directory -Path $PLUGINS_DIR -Force | Out-Null
        }

        Set-Status "Stopping Stream Deck..." 30
        $wasRunning = $null -ne (Get-SDProcess)
        if ($wasRunning) { Stop-SD }

        Set-Status "Removing old version..." 45
        if (Test-Path $DEST_PATH) { Remove-Item $DEST_PATH -Recurse -Force }
        New-Item -ItemType Directory -Path $DEST_PATH -Force | Out-Null

        Set-Status "Extracting plugin files..." 60

        $zipArchive = [System.IO.Compression.ZipFile]::OpenRead($tmp)
        foreach ($entry in $zipArchive.Entries) {
            $destFile = Join-Path $PLUGINS_DIR $entry.FullName.Replace("/", "\")
            $destDir  = Split-Path $destFile -Parent
            if (-not (Test-Path $destDir)) { New-Item -ItemType Directory $destDir -Force | Out-Null }
            if (-not $entry.FullName.EndsWith("/")) {
                [System.IO.Compression.ZipFileExtensions]::ExtractToFile($entry, $destFile, $true)
            }
        }
        $zipArchive.Dispose()
        Remove-Item $tmp -Force

        Set-Status "Verifying..." 80
        if (-not (Test-Path (Join-Path $DEST_PATH "manifest.json"))) {
            throw "manifest.json not found after extraction"
        }

        Set-Status "Restarting Stream Deck..." 92
        if ($wasRunning) { Start-SD }

        Set-Status "Installation complete!" 100
        $script:btnOK.Text      = "Done ✓"
        $script:btnOK.BackColor = [System.Drawing.Color]::FromArgb(0, 160, 80)
        $script:btnCancel.Text  = "Close"
        $script:btnCancel.Enabled = $true

        Show-MB "Language Switcher installed successfully!`n`nOpen Stream Deck, find 'Language Switcher' in the actions panel, and drag it onto a button.`n`nEnjoy! — iH4xz" `
            "Installation Complete" "Information"

    } catch {
        Set-Status "Error: $_" 0
        Show-MB "Installation failed:`n`n$_`n`nPlease report at:`nhttps://github.com/iH4xz/lang-switcher-btn/issues" `
            "Installation Error" "Error"
        $script:btnOK.Enabled     = $true
        $script:btnCancel.Enabled = $true
    }
}

[System.Windows.Forms.Application]::EnableVisualStyles()
$frm = Show-Form
$frm.ShowDialog() | Out-Null
